pipeline.evaluate:
(() => {
  const limit = parseInt('${{ args.limit }}');
  const items = [];
  const cells = document.querySelectorAll('[data-testid="trend"]');

  cells.forEach(cell => {
    const text = cell.textContent || '';
    if (text.includes('Promoted')) return;

    const spans = cell.querySelectorAll('span');
    let topic = '';
    for (const span of spans) {
      const t = span.textContent.trim();
      if (t && !t.match(/^\d+$/) && !t.includes('Trending') && !t.includes('posts')) {
        topic = t;
        break;
      }
    }

    if (topic) items.push({ rank: items.length + 1, topic, tweets: 'N/A', category: '' });
  });

  return items.slice(0, limit);
})()
